{{#ifexpr: ({{{1|0}}}) < 0 | {{#expr:abs({{{1|0}}})}} BC | {{#expr:{{{1|0}}} + 0}} }}<noinclude>

{{Documentation|content =
This subtemplate is used to strip leading zeros and convert negative years to years BC.  It should not be used directly.

== Examples ==

* <code><nowiki>{{State establishment category/year| 50 }}</nowiki></code> &rarr; {{State establishment category/year| 50 }}
* <code><nowiki>{{State establishment category/year| 00 }}</nowiki></code> &rarr; {{State establishment category/year| 00 }}
* <code><nowiki>{{State establishment category/year|-50 }}</nowiki></code> &rarr; {{State establishment category/year|-50 }}

}}</noinclude>

